const items = $input.all();
const results = [];

for (const item of items) {
  const binary = item.binary || {};
  const binaryKeys = Object.keys(binary);
  if (!binaryKeys.length) {
    throw new Error('No PDF binary payload was provided to the processing core.');
  }

  let pdfKey = 'pdf';
  if (!binary[pdfKey]) {
    for (const key of binaryKeys) {
      const file = binary[key] || {};
      const fileName = String(file.fileName || '').toLowerCase();
      const mimeType = String(file.mimeType || '').toLowerCase();
      if (mimeType === 'application/pdf' || fileName.endsWith('.pdf')) {
        pdfKey = key;
        break;
      }
    }
    if (!binary[pdfKey]) {
      pdfKey = binaryKeys[0];
    }
  }

  const pdf = binary[pdfKey];
  const sourceJson = item.json || {};
  const rawReceivedDate = sourceJson.received_date || sourceJson.receivedDate || null;
  let receivedDate = null;
  if (rawReceivedDate != null && rawReceivedDate !== '') {
    const str = String(rawReceivedDate).trim();
    const iso = str.match(/^(\d{4})-(\d{2})-(\d{2})/);
    const dmy = str.match(/^(\d{1,2})[./-](\d{1,2})[./-](\d{2,4})$/);
    const monthYear = str.match(/^(\d{1,2})[./-](\d{4})$/);
    if (iso) {
      receivedDate = iso[1] + '-' + iso[2] + '-' + iso[3];
    } else if (dmy) {
      const year = dmy[3].length === 2 ? '20' + dmy[3] : dmy[3];
      receivedDate = year + '-' + dmy[2].padStart(2, '0') + '-' + dmy[1].padStart(2, '0');
    } else if (monthYear) {
      receivedDate = monthYear[2] + '-' + monthYear[1].padStart(2, '0') + '-01';
    } else {
      const dateValue = new Date(str);
      if (!Number.isNaN(dateValue.getTime())) {
        receivedDate = dateValue.toISOString().slice(0, 10);
      }
    }
  }
  if (!receivedDate) {
    receivedDate = new Date().toISOString().slice(0, 10);
  }

  const duplicateMode = ['skip', 'overwrite', 'reprocess'].includes(sourceJson.duplicate_mode)
    ? sourceJson.duplicate_mode
    : 'overwrite';
  const persistenceMode = sourceJson.persistence_mode === 'none' ? 'none' : 'postgres';
  const persistResult = !(sourceJson.persist_result === false || sourceJson.persist_result === 'false');
  const ingestionChannel = ['form', 'webhook', 'email'].includes(sourceJson.ingestion_channel)
    ? sourceJson.ingestion_channel
    : 'manual';

  results.push({
    json: {
      source_filename: sourceJson.source_filename || pdf.fileName || 'unknown.pdf',
      ingestion_channel: ingestionChannel,
      received_date: receivedDate,
      duplicate_mode: duplicateMode,
      persist_result: persistResult,
      persistence_mode: persistenceMode,
    },
    binary: { pdf },
  });
}

return results;

const items = $input.all();
const normalizedItems = $('Normalize Intake Payload').all();

return items.map((item, index) => {
  const source = item.json || {};
  const normalizedItem = normalizedItems[index] || normalizedItems[0] || {};
  const sourceBinary = (item.binary && Object.keys(item.binary).length > 0)
    ? item.binary
    : (normalizedItem.binary || {});

  return {
    json: {
      received_date: source.received_date || null,
      provider: null,
      provider_contact: {
