        status: 'pending',
        validation_errors: [],
      },
      _runtime: {
        duplicate_mode: source.duplicate_mode || 'overwrite',
        persist_result: source.persist_result !== false,
        persistence_mode: source.persistence_mode || 'postgres',
        duplicate_lookup_requested: source.persist_result !== false && source.persistence_mode !== 'none' ? 1 : null,
        duplicate_found: false,
        reuse_existing_marker: null,
        reused_payload: null,
        duplicate_lookup_error: null,
        extracted_text: null,
        expose_location_description: null,
        ai_error: null,
        enrichment_failed: false,
        persistence_error: null,
        persist_result_marker: null,
      },
    },
    binary: sourceBinary,
  };
});

const baseItem = $('Initialize Extraction Context').first();
const base = JSON.parse(JSON.stringify(baseItem.json || {}));
const binary = baseItem.binary || {};
const lookupItem = $input.first();
const lookup = lookupItem ? (lookupItem.json || {}) : {};
const runtime = base._runtime && typeof base._runtime === 'object' ? base._runtime : {};

if (lookup.error) {
  runtime.duplicate_lookup_error = lookup.error.message || String(lookup.error);
}

if (runtime.persist_result && runtime.persistence_mode === 'postgres' && lookup.found === true) {
  runtime.duplicate_found = true;
}

if (runtime.persist_result && runtime.persistence_mode === 'postgres' && runtime.duplicate_mode === 'skip' && lookup.found === true && lookup.payload_jsonb) {
  let reusedPayload = lookup.payload_jsonb;
  if (typeof reusedPayload === 'string') {
    reusedPayload = JSON.parse(reusedPayload);
  }
  if (!reusedPayload.processing_metadata || typeof reusedPayload.processing_metadata !== 'object') {
    reusedPayload.processing_metadata = {};
  }
  if (!Array.isArray(reusedPayload.processing_metadata.validation_errors)) {
    reusedPayload.processing_metadata.validation_errors = [];
  }
  reusedPayload.processing_metadata.status = 'duplicate_skipped';
  runtime.reuse_existing_marker = 1;
  runtime.reused_payload = reusedPayload;
}

base._runtime = runtime;
return [{ json: base, binary }];

var inputItem = $input.first() || {};
var currentJson = inputItem.json || {};
var payload = JSON.parse(JSON.stringify((currentJson._runtime && currentJson._runtime.reused_payload) || {}));
if (!payload.processing_metadata || typeof payload.processing_metadata !== 'object') {
  payload.processing_metadata = {};
}
if (!Array.isArray(payload.processing_metadata.validation_errors)) {
  payload.processing_metadata.validation_errors = [];
}
payload.processing_metadata.status = 'duplicate_skipped';
return [{ json: payload }];

const payload = JSON.parse(JSON.stringify($input.first().json || {}));
const candidate = JSON.parse(JSON.stringify(payload));
delete candidate._runtime;

const nullableString = { type: ['string', 'null'] };
const nullableNumber = { type: ['number', 'null'] };
const nullableBoolean = { type: ['boolean', 'null'] };
const infrastructureItem = {
  type: 'object',
  additionalProperties: false,
  required: ['category', 'name', 'address', 'rating'],
  properties: {
    category: nullableString,
    name: nullableString,
    address: nullableString,
    rating: nullableNumber,
  },
};

const schema = {
  type: 'object',
  additionalProperties: false,
  required: [
    'received_date',
    'provider',
    'provider_contact',
    'owner',
    'address',
    'areas',
    'financials',
    'property',
    'returns',
    'notes',
    'location_enrichment',
    'market_context',
    'processing_metadata',
  ],
  properties: {
    received_date: nullableString,
    provider: nullableString,
    provider_contact: {
      type: 'object',
      additionalProperties: false,
      required: ['name', 'company', 'phone', 'email'],
      properties: {
        name: nullableString,
        company: nullableString,
        phone: nullableString,
        email: nullableString,
      },
    },
    owner: nullableString,
    address: {
      type: 'object',
      additionalProperties: false,
      required: ['country', 'postal_code', 'city', 'street', 'house_number'],
      properties: {
        country: nullableString,
        postal_code: nullableString,
        city: nullableString,
        street: nullableString,
        house_number: nullableString,
      },
    },
    areas: {
      type: 'object',
      additionalProperties: false,
      required: ['usable_area_m2', 'plot_area_m2'],
      properties: {
        usable_area_m2: nullableNumber,
        plot_area_m2: nullableNumber,
      },
    },
    financials: {
      type: 'object',
      additionalProperties: false,
      required: ['target_rent_pa_eur', 'actual_rent_pa_eur', 'asking_price_eur', 'price_per_m2_usable_area', 'price_per_m2_land'],
      properties: {
        target_rent_pa_eur: nullableNumber,
        actual_rent_pa_eur: nullableNumber,
        asking_price_eur: nullableNumber,
        price_per_m2_usable_area: nullableNumber,
        price_per_m2_land: nullableNumber,
      },
    },
    property: {
      type: 'object',
      additionalProperties: false,
      required: ['property_type', 'ownership_type', 'construction_year', 'heritage_protection', 'vacancy', 'parking_spaces'],
      properties: {
        property_type: nullableString,
        ownership_type: nullableString,
        construction_year: nullableNumber,
        heritage_protection: nullableBoolean,
        vacancy: nullableNumber,
        parking_spaces: nullableNumber,
      },
    },
    returns: {
      type: 'object',
      additionalProperties: false,
      required: ['gross_initial_yield_actual', 'gross_initial_yield_target'],
      properties: {
        gross_initial_yield_actual: nullableNumber,
        gross_initial_yield_target: nullableNumber,
      },
    },
    notes: nullableString,
    location_enrichment: {
      type: 'object',
      additionalProperties: false,
      required: ['latitude', 'longitude', 'aerial_image_url', 'location_description', 'public_transport_access', 'distance_city_center_min', 'distance_train_station_min', 'distance_airport_min', 'infrastructure'],
      properties: {
        latitude: nullableNumber,
        longitude: nullableNumber,
        aerial_image_url: nullableString,
        location_description: nullableString,
        public_transport_access: nullableString,
        distance_city_center_min: nullableNumber,
        distance_train_station_min: nullableNumber,
        distance_airport_min: nullableNumber,
        infrastructure: {
          type: 'array',
          items: infrastructureItem,
        },
      },
    },
    market_context: {
      type: 'object',
      additionalProperties: false,
      required: ['potential_revenue', 'demographics'],
      properties: {
        potential_revenue: nullableString,
        demographics: {
          type: 'object',
          additionalProperties: false,
          required: ['population_development', 'purchasing_power'],
          properties: {
            population_development: nullableString,
            purchasing_power: nullableString,
          },
        },
      },
    },
    processing_metadata: {
      type: 'object',
      additionalProperties: false,
      required: ['document_id', 'source_filename', 'ingestion_channel', 'processed_at', 'status', 'validation_errors'],
      properties: {
        document_id: nullableString,
        source_filename: nullableString,
        ingestion_channel: nullableString,
        processed_at: nullableString,
        status: nullableString,
        validation_errors: {
          type: 'array',
          items: { type: 'string' },
        },
      },
    },
  },
};

const systemPrompt = [
  'You normalize Austrian and German real estate expose text into a strict JSON object.',
  'Use the provided deterministic candidate values when they appear correct and only fill missing or ambiguous fields.',
  'Return null for anything not present.',
  'Do not add fields, comments, markdown, or explanations.',
  'Do not compute derived fields such as price_per_m2_* or gross_initial_yield_* unless explicitly stated in the document. Leave them null if they are not directly stated.',
  'Keep enums exactly as provided for property_type and ownership_type.',
].join(' ');

const documentText = String(payload._runtime && payload._runtime.extracted_text ? payload._runtime.extracted_text : '').slice(0, 60000);
const candidateJson = JSON.stringify(candidate, null, 2).slice(0, 20000);

payload.openai_request_body = {
  model: 'gpt-4.1-mini',
  temperature: 0,
  input: [
    {
      role: 'system',
      content: [
        {
          type: 'input_text',
          text: systemPrompt,
        },
      ],
    },
    {
      role: 'user',
      content: [
        {
          type: 'input_text',
          text: [
            'Map the exposé into the target schema and only improve missing or ambiguous values.',
            'Document text:',
            documentText,
            '',
            'Deterministic candidate JSON:',
            candidateJson,
          ].join('\n'),
        },
      ],
    },
  ],
  text: {
    format: {
      type: 'json_schema',
      name: 'real_estate_expose',
      strict: true,
      schema,
    },
  },
};

return [{ json: payload }];

const payload = JSON.parse(JSON.stringify($('Parse Expose Deterministically').first().json || {}));
const response = $input.first()?.json || {};
const runtime = payload._runtime && typeof payload._runtime === 'object' ? payload._runtime : {};

function parseGermanNumber(value) {
  let parsed = null;
  if (value != null && value !== '') {
    if (typeof value === 'number') {
      parsed = Number.isFinite(value) ? value : null;
    } else {
      let text = String(value).trim();
      text = text.replace(/\u00a0/g, ' ');
      text = text.replace(/(eur|euro|m²|m2|qm|prozent|%|m)\b/gi, '');
      text = text.replace(/\s+/g, '');
      text = text.replace(/,-/g, '');
      if (text.indexOf(',') !== -1 && text.indexOf('.') !== -1) {
        text = text.replace(/\./g, '').replace(',', '.');
      } else if (text.indexOf(',') !== -1) {
        text = text.replace(',', '.');
      } else {
        text = text.replace(/(\d)\.(?=\d{3}(\D|$))/g, '$1');
      }
      const numericValue = Number(text);
      parsed = Number.isFinite(numericValue) ? numericValue : null;
    }
  }
  return { value: parsed };
}

function getPath(target, path) {
  const parts = path.split('.');
  let current = target;
  for (const part of parts) {
    if (current == null || typeof current !== 'object' || !(part in current)) {
      return { value: undefined };
    }
    current = current[part];
  }
  return { value: current };
}

function setPath(target, path, value) {
  const parts = path.split('.');
  let current = target;
  for (let i = 0; i < parts.length - 1; i += 1) {
    if (!current[parts[i]] || typeof current[parts[i]] !== 'object') current[parts[i]] = {};
    current = current[parts[i]];
  }
  current[parts[parts.length - 1]] = value;
}

let aiPayload = null;
let aiError = response.error?.message || response.error || null;
const candidateTexts = [];
if (Array.isArray(response.output)) {
  for (const outputItem of response.output) {
    const contentItems = outputItem && Array.isArray(outputItem.content) ? outputItem.content : [];
    for (const contentItem of contentItems) {
      if (contentItem && typeof contentItem.text === 'string' && contentItem.text.trim()) candidateTexts.push(contentItem.text);
      if (!aiPayload && contentItem && contentItem.json && typeof contentItem.json === 'object') aiPayload = contentItem.json;
    }
  }
}
if (!aiPayload && typeof response.text === 'string' && response.text.trim()) candidateTexts.push(response.text);
if (!aiPayload) {
  for (const candidateText of candidateTexts) {
    try {
      aiPayload = JSON.parse(candidateText);
      break;
    } catch (error) {
      aiError = aiError || error.message;
    }
  }
}
if (!aiPayload || typeof aiPayload !== 'object') aiPayload = {};

const stringPaths = [
  'received_date','provider','provider_contact.name','provider_contact.company','provider_contact.phone','provider_contact.email','owner','address.country','address.postal_code','address.city','address.street','address.house_number','property.property_type','property.ownership_type','notes','location_enrichment.aerial_image_url','location_enrichment.location_description','location_enrichment.public_transport_access','market_context.potential_revenue','market_context.demographics.population_development','market_context.demographics.purchasing_power','processing_metadata.document_id','processing_metadata.source_filename','processing_metadata.ingestion_channel','processing_metadata.processed_at','processing_metadata.status'
];
for (const path of stringPaths) {
  const currentValue = getPath(payload, path).value;
  const aiValue = getPath(aiPayload, path).value;
  if ((currentValue == null || currentValue === '') && aiValue != null && aiValue !== '') setPath(payload, path, String(aiValue));
}

const numericPaths = [
  'areas.usable_area_m2','areas.plot_area_m2','financials.target_rent_pa_eur','financials.actual_rent_pa_eur','financials.asking_price_eur','financials.price_per_m2_usable_area','financials.price_per_m2_land','property.construction_year','property.vacancy','property.parking_spaces','returns.gross_initial_yield_actual','returns.gross_initial_yield_target','location_enrichment.latitude','location_enrichment.longitude','location_enrichment.distance_city_center_min','location_enrichment.distance_train_station_min','location_enrichment.distance_airport_min'
];
for (const path of numericPaths) {
  const currentValue = getPath(payload, path).value;
  const aiValue = getPath(aiPayload, path).value;
  if (currentValue == null && aiValue != null && aiValue !== '') setPath(payload, path, parseGermanNumber(aiValue).value);
}

const currentHeritage = getPath(payload, 'property.heritage_protection').value;
const aiHeritage = getPath(aiPayload, 'property.heritage_protection').value;
if (currentHeritage == null && aiHeritage != null) {
  if (typeof aiHeritage === 'boolean') payload.property.heritage_protection = aiHeritage;
  else {
    const lower = String(aiHeritage).toLowerCase();
    if (/^(ja|yes|true|1|denkmal)/.test(lower)) payload.property.heritage_protection = true;
    else if (/^(nein|no|false|0|kein)/.test(lower)) payload.property.heritage_protection = false;
  }
}

if ((!payload.location_enrichment.infrastructure || !payload.location_enrichment.infrastructure.length) && Array.isArray(aiPayload.location_enrichment && aiPayload.location_enrichment.infrastructure)) {
  const infrastructure = [];
  for (const entry of aiPayload.location_enrichment.infrastructure) {
    infrastructure.push({
      category: entry && entry.category != null ? String(entry.category) : null,
      name: entry && entry.name != null ? String(entry.name) : null,
      address: entry && entry.address != null ? String(entry.address) : null,
      distance_m: entry && entry.distance_m != null ? parseGermanNumber(entry.distance_m).value : null,
    });
  }
  payload.location_enrichment.infrastructure = infrastructure;
}

if (!payload.provider_contact.company && payload.provider) payload.provider_contact.company = payload.provider;
if (runtime.expose_location_description && !payload.location_enrichment.location_description) payload.location_enrichment.location_description = runtime.expose_location_description;

function roundToTwo(value) {
  let rounded = null;
  if (value != null && Number.isFinite(value)) rounded = Math.round(value * 100) / 100;
  return { value: rounded };
}

const askingPrice = payload.financials.asking_price_eur;
const usableArea = payload.areas.usable_area_m2;
const plotArea = payload.areas.plot_area_m2;
const actualRent = payload.financials.actual_rent_pa_eur;
const targetRent = payload.financials.target_rent_pa_eur;
payload.financials.price_per_m2_usable_area = askingPrice != null && usableArea ? roundToTwo(askingPrice / usableArea).value : null;
payload.financials.price_per_m2_land = askingPrice != null && plotArea ? roundToTwo(askingPrice / plotArea).value : null;
payload.returns.gross_initial_yield_actual = askingPrice != null && actualRent != null ? roundToTwo((actualRent / askingPrice) * 100).value : null;
payload.returns.gross_initial_yield_target = askingPrice != null && targetRent != null ? roundToTwo((targetRent / askingPrice) * 100).value : null;

payload._runtime = {
  ...runtime,
  ai_error: aiError,
};

return [{ json: payload }];

const payload = JSON.parse(JSON.stringify($input.first().json || {}));
const runtime = payload._runtime && typeof payload._runtime === 'object' ? payload._runtime : {};

function createSchema() {
  return {
    received_date: null,
    provider: null,
    provider_contact: { name: null, company: null, phone: null, email: null },
    owner: null,
    address: { country: 'Austria', postal_code: null, city: null, street: null, house_number: null },
    areas: { usable_area_m2: null, plot_area_m2: null },
    financials: { target_rent_pa_eur: null, actual_rent_pa_eur: null, asking_price_eur: null, price_per_m2_usable_area: null, price_per_m2_land: null },
    property: { property_type: null, ownership_type: null, construction_year: null, heritage_protection: null, vacancy: null, parking_spaces: null },
    returns: { gross_initial_yield_actual: null, gross_initial_yield_target: null },
    notes: null,
    location_enrichment: { latitude: null, longitude: null, aerial_image_url: null, location_description: null, public_transport_access: null, distance_city_center_min: null, distance_train_station_min: null, distance_airport_min: null, infrastructure: [] },
    market_context: { potential_revenue: null, demographics: { population_development: null, purchasing_power: null } },
    processing_metadata: { document_id: null, source_filename: null, ingestion_channel: null, processed_at: null, status: null, validation_errors: [] },
    _runtime: runtime,
  };
}

function overlay(target, source) {
  for (const key of Object.keys(target)) {
    if (!(key in source)) continue;
    if (Array.isArray(target[key])) {
      target[key] = Array.isArray(source[key]) ? source[key] : target[key];
    } else if (target[key] && typeof target[key] === 'object' && source[key] && typeof source[key] === 'object') {
      overlay(target[key], source[key]);
    } else {
      target[key] = source[key];
    }
  }
}

function isNumberOrNull(value) {
  return value === null || (typeof value === 'number' && Number.isFinite(value));
}

const normalized = createSchema();
overlay(normalized, payload);
if (!Array.isArray(normalized.processing_metadata.validation_errors)) {
  normalized.processing_metadata.validation_errors = [];
}
if (!Array.isArray(normalized.location_enrichment.infrastructure)) {
  normalized.location_enrichment.infrastructure = [];
}

const validationErrors = [];
const numericPaths = [
  ['areas', 'usable_area_m2'],
  ['areas', 'plot_area_m2'],
  ['financials', 'target_rent_pa_eur'],
  ['financials', 'actual_rent_pa_eur'],
  ['financials', 'asking_price_eur'],
  ['financials', 'price_per_m2_usable_area'],
  ['financials', 'price_per_m2_land'],
  ['property', 'construction_year'],
  ['property', 'vacancy'],
  ['property', 'parking_spaces'],
  ['returns', 'gross_initial_yield_actual'],
  ['returns', 'gross_initial_yield_target'],
  ['location_enrichment', 'latitude'],
  ['location_enrichment', 'longitude'],
  ['location_enrichment', 'distance_city_center_min'],
  ['location_enrichment', 'distance_train_station_min'],
  ['location_enrichment', 'distance_airport_min'],
];
for (const [group, key] of numericPaths) {
  if (!isNumberOrNull(normalized[group][key])) {
    validationErrors.push('numeric_field_invalid:' + group + '.' + key);
    normalized[group][key] = null;
  }
}

if (!normalized.provider) validationErrors.push('missing_business_critical:provider');
if (!(normalized.address.city || normalized.address.postal_code || normalized.address.street)) validationErrors.push('missing_business_critical:address');
if (!normalized.property.property_type) validationErrors.push('missing_business_critical:property.property_type');
